#!/bin/bash

# Keyword Ranking Checker Agent - Setup Script
# This script generates all necessary project files and directory structure

set -e  # Exit on error

echo "🚀 Keyword Ranking Checker Agent - Setup Script"
echo "=================================================="
echo ""

# Colors for output
GREEN='\033[0;32m'\nBLUE='\033[0;34m'\nYELLOW='\033[1;33m'\nNC='\033[0m' # No Color

# Function to print colored output
print_status() {\n    echo -e "${BLUE}[*]${NC} $1"\n}\n\nprint_success() {\n    echo -e "${GREEN}[✓]${NC} $1"\n}\n\nprint_warning() {\n    echo -e "${YELLOW}[!]${NC} $1\"\n}\n\n# Create directory structure\nprint_status \"Creating directory structure...\"\nmkdir -p src\nmkdir -p tests\nmkdir -p .github/workflows\nmkdir -p reports\nmkdir -p logs\nmkdir -p data\nprint_success \"Directories created\"\n\n# Create src/__init__.py\nprint_status \"Creating src/__init__.py...\"\ncat > src/__init__.py << 'EOF'\n\"\"\"Keyword Rank Checker package\"\"\"\n\n__version__ = '1.0.0'\n__author__ = 'Keyword Rank Checker Team'\nEOF\nprint_success \"Created src/__init__.py\"\n\n# Create src/rank_checker.py\nprint_status \"Creating src/rank_checker.py...\"\ncat > src/rank_checker.py << 'EOF'\n\"\"\"Rank checker module for keyword position tracking\"\"\"\n\nimport logging\nimport requests\nfrom typing import Dict, List, Optional\nfrom urllib.parse import urljoin\nfrom bs4 import BeautifulSoup\n\nlogger = logging.getLogger(__name__)\n\n\nclass RankChecker:\n    \"\"\"Check keyword rankings using various methods\"\"\"\n    \n    def __init__(self, api_config: Dict):\n        \"\"\"Initialize rank checker\n        \n        Args:\n            api_config: API configuration dictionary\n        \"\"\"\n        self.provider = api_config.get('provider', 'serper')\n        self.api_key = api_config.get('serper_api_key')\n        self.max_results = api_config.get('max_results', 100)\n        self.timeout = api_config.get('timeout', 30)\n    \n    def check_keyword(\n        self,\n        keyword: str,\n        target_url: str,\n        location: str = 'US',\n        language: str = 'en'\n    ) -> Dict:\n        \"\"\"Check ranking for a keyword\n        \n        Args:\n            keyword: The keyword to check\n            target_url: The target URL to find in results\n            location: Geographic location for search\n            language: Language for search\n            \n        Returns:\n            Dictionary with ranking data\n        \"\"\"\n        logger.info(f\"Checking keyword: {keyword} for URL: {target_url}\")\n        \n        if self.provider == 'serper':\n            return self._check_with_serper(keyword, target_url, location, language)\n        else:\n            return self._check_with_google_api(keyword, target_url)\n    \n    def _check_with_serper(\n        self,\n        keyword: str,\n        target_url: str,\n        location: str,\n        language: str\n    ) -> Dict:\n        \"\"\"Check ranking using Serper API\"\"\"\n        url = \"https://google.serper.dev/search\"\n        \n        payload = {\n            \"q\": keyword,\n            \"gl\": location.lower(),\n            \"hl\": language,\n            \"num\": min(self.max_results, 100)\n        }\n        \n        headers = {\n            \"X-API-KEY\": self.api_key,\n            \"Content-Type\": \"application/json\"\n        }\n        \n        try:\n            response = requests.post(\n                url,\n                json=payload,\n                headers=headers,\n                timeout=self.timeout\n            )\n            response.raise_for_status()\n            \n            data = response.json()\n            results = data.get('organic', [])\n            \n            # Find target URL in results\n            position = None\n            for idx, result in enumerate(results, 1):\n                if self._url_match(result.get('link', ''), target_url):\n                    position = idx\n                    break\n            \n            if position is None:\n                position = 0  # Not in top results\n            \n            return {\n                'keyword': keyword,\n                'target_url': target_url,\n                'position': position,\n                'url': results[position-1].get('link') if position > 0 else '',\n                'title': results[position-1].get('title') if position > 0 else '',\n                'serp_features': data.get('searchParameters', {}).get('type', []),\n                'total_results': data.get('searchInformation', {}).get('total', 0)\n            }\n            \n        except requests.exceptions.RequestException as e:\n            logger.error(f\"Serper API error: {str(e)}\")\n            raise\n    \n    def _check_with_google_api(self, keyword: str, target_url: str) -> Dict:\n        \"\"\"Check ranking using Google Custom Search API\"\"\"\n        logger.warning(\"Google Custom Search API not implemented yet\")\n        return {\n            'keyword': keyword,\n            'target_url': target_url,\n            'position': 0,\n            'error': 'Not implemented'\n        }\n    \n    def _url_match(self, result_url: str, target_url: str) -> bool:\n        \"\"\"Check if URLs match (handles various formats)\"\"\"\n        result_domain = result_url.replace('https://', '').replace('http://', '').split('/')[0]\n        target_domain = target_url.replace('https://', '').replace('http://', '').split('/')[0]\n        \n        return result_domain == target_domain or result_url.startswith(target_url)\n\n\nclass BulkRankChecker(RankChecker):\n    \"\"\"Check rankings for multiple keywords\"\"\"\n    \n    def check_multiple(self, keywords: List[Dict]) -> List[Dict]:\n        \"\"\"Check multiple keywords\"\"\"\n        results = []\n        for kw_config in keywords:\n            result = self.check_keyword(\n                keyword=kw_config['keyword'],\n                target_url=kw_config['target_url'],\n                location=kw_config.get('location', 'US'),\n                language=kw_config.get('language', 'en')\n            )\n            results.append(result)\n        \n        return results\nEOF\nprint_success \"Created src/rank_checker.py\"\n\n# Create src/database.py\nprint_status \"Creating src/database.py...\"\ncat > src/database.py << 'EOF'\n\"\"\"Database module for storing ranking history\"\"\"\n\nimport sqlite3\nimport logging\nfrom datetime import datetime, timedelta\nfrom typing import List, Dict, Optional\nfrom pathlib import Path\n\nlogger = logging.getLogger(__name__)\n\n\nclass Database:\n    \"\"\"SQLite database for ranking data\"\"\"\n    \n    def __init__(self, db_config: Dict):\n        \"\"\"Initialize database\"\"\"\n        self.db_type = db_config.get('type', 'sqlite')\n        self.db_path = db_config.get('path', './data/rankings.db')\n        self.backup_enabled = db_config.get('backup_enabled', True)\n        \n        Path(self.db_path).parent.mkdir(parents=True, exist_ok=True)\n        self._init_db()\n    \n    def _init_db(self):\n        \"\"\"Initialize database tables\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            cursor = conn.cursor()\n            \n            cursor.execute('''\n                CREATE TABLE IF NOT EXISTS rankings (\n                    id INTEGER PRIMARY KEY AUTOINCREMENT,\n                    keyword TEXT NOT NULL,\n                    target_url TEXT NOT NULL,\n                    position INTEGER,\n                    url TEXT,\n                    title TEXT,\n                    serp_features TEXT,\n                    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP\n                )\n            ''')\n            \n            cursor.execute('''\n                CREATE INDEX IF NOT EXISTS idx_keyword_timestamp \n                ON rankings(keyword, timestamp)\n            ''')\n            \n            cursor.execute('''\n                CREATE INDEX IF NOT EXISTS idx_target_url_timestamp \n                ON rankings(target_url, timestamp)\n            ''')\n            \n            conn.commit()\n            conn.close()\n            logger.info(f\"Database initialized at {self.db_path}\")\n            \n        except sqlite3.Error as e:\n            logger.error(f\"Database initialization error: {str(e)}\")\n            raise\n    \n    def store_ranking(self, keyword: str, target_url: str, position: Optional[int] = None,\n                     url: Optional[str] = None, title: Optional[str] = None,\n                     serp_features: Optional[List[str]] = None) -> int:\n        \"\"\"Store ranking data\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            cursor = conn.cursor()\n            \n            serp_features_str = ','.join(serp_features) if serp_features else ''\n            \n            cursor.execute('''\n                INSERT INTO rankings \n                (keyword, target_url, position, url, title, serp_features)\n                VALUES (?, ?, ?, ?, ?, ?)\n            ''', (keyword, target_url, position, url, title, serp_features_str))\n            \n            conn.commit()\n            row_id = cursor.lastrowid\n            conn.close()\n            \n            logger.info(f\"Stored ranking: {keyword} at position {position}\")\n            return row_id\n            \n        except sqlite3.Error as e:\n            logger.error(f\"Error storing ranking: {str(e)}\")\n            raise\n    \n    def get_latest_rankings(self, keyword: Optional[str] = None) -> List[Dict]:\n        \"\"\"Get latest rankings\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            conn.row_factory = sqlite3.Row\n            cursor = conn.cursor()\n            \n            if keyword:\n                cursor.execute('SELECT * FROM rankings WHERE keyword = ? ORDER BY timestamp DESC LIMIT 1',\n                             (keyword,))\n            else:\n                cursor.execute('''\n                    SELECT * FROM rankings WHERE (keyword, timestamp) IN (\n                        SELECT keyword, MAX(timestamp) FROM rankings \n                        GROUP BY keyword\n                    )\n                    ORDER BY keyword\n                ''')\n            \n            results = [dict(row) for row in cursor.fetchall()]\n            conn.close()\n            \n            return results\n            \n        except sqlite3.Error as e:\n            logger.error(f\"Error fetching latest rankings: {str(e)}\")\n            raise\n    \n    def get_ranking_history(self, keyword: Optional[str] = None, days: int = 30) -> List[Dict]:\n        \"\"\"Get ranking history for period\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            conn.row_factory = sqlite3.Row\n            cursor = conn.cursor()\n            \n            date_from = datetime.now() - timedelta(days=days)\n            date_from_str = date_from.isoformat()\n            \n            if keyword:\n                cursor.execute('''\n                    SELECT * FROM rankings \n                    WHERE keyword = ? AND timestamp >= ? \n                    ORDER BY timestamp ASC\n                ''', (keyword, date_from_str))\n            else:\n                cursor.execute('''\n                    SELECT * FROM rankings \n                    WHERE timestamp >= ? \n                    ORDER BY keyword, timestamp ASC\n                ''', (date_from_str,))\n            \n            results = [dict(row) for row in cursor.fetchall()]\n            conn.close()\n            \n            logger.info(f\"Retrieved {len(results)} historical records from last {days} days\")\n            return results\n            \n        except sqlite3.Error as e:\n            logger.error(f\"Error fetching ranking history: {str(e)}\")\n            raise\nEOF\nprint_success \"Created src/database.py\"\n\n# Create src/report_generator.py\nprint_status \"Creating src/report_generator.py...\"\ncat > src/report_generator.py << 'EOF'\n\"\"\"Report generation module\"\"\"\n\nimport json\nimport csv\nimport logging\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import Dict, List\n\nlogger = logging.getLogger(__name__)\n\n\nclass ReportGenerator:\n    \"\"\"Generate ranking reports in multiple formats\"\"\"\n    \n    def __init__(self, report_config: Dict):\n        \"\"\"Initialize report generator\"\"\"\n        self.output_dir = Path(report_config.get('output_dir', './reports'))\n        self.output_dir.mkdir(exist_ok=True)\n        self.export_formats = report_config.get('export_formats', ['json', 'csv'])\n    \n    def generate(self, latest_rankings: List[Dict], history: List[Dict], timestamp: datetime) -> Dict:\n        \"\"\"Generate comprehensive report\"\"\"\n        report = {\n            'timestamp': timestamp.isoformat(),\n            'summary': {\n                'total_keywords': len(latest_rankings),\n                'tracked_keywords': len([r for r in latest_rankings if r.get('position')])\n            },\n            'rankings': latest_rankings,\n            'rankings_by_position': self._group_by_position(latest_rankings),\n            'top_performers': self._get_top_performers(latest_rankings),\n            'history': history\n        }\n        \n        logger.info(f\"Report generated with {len(latest_rankings)} keywords\")\n        return report\n    \n    def export(self, report: Dict, export_format: str) -> Path:\n        \"\"\"Export report in specified format\"\"\"\n        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')\n        \n        if export_format == 'json':\n            return self._export_json(report, timestamp)\n        elif export_format == 'csv':\n            return self._export_csv(report, timestamp)\n        else:\n            raise ValueError(f\"Unsupported format: {export_format}\")\n    \n    def _export_json(self, report: Dict, timestamp: str) -> Path:\n        \"\"\"Export report as JSON\"\"\"\n        filename = self.output_dir / f\"ranking_report_{timestamp}.json\"\n        \n        try:\n            with open(filename, 'w') as f:\n                json.dump(report, f, indent=2, default=str)\n            \n            logger.info(f\"JSON report exported to {filename}\")\n            return filename\n            \n        except Exception as e:\n            logger.error(f\"Error exporting JSON report: {str(e)}\")\n            raise\n    \n    def _export_csv(self, report: Dict, timestamp: str) -> Path:\n        \"\"\"Export report as CSV\"\"\"\n        filename = self.output_dir / f\"ranking_report_{timestamp}.csv\"\n        \n        try:\n            rankings = report.get('rankings', [])\n            \n            if not rankings:\n                logger.warning(\"No rankings to export\")\n                return filename\n            \n            with open(filename, 'w', newline='') as f:\n                fieldnames = ['keyword', 'target_url', 'position', 'title', 'url', 'timestamp']\n                writer = csv.DictWriter(f, fieldnames=fieldnames)\n                \n                writer.writeheader()\n                for ranking in rankings:\n                    writer.writerow({\n                        'keyword': ranking.get('keyword', ''),\n                        'target_url': ranking.get('target_url', ''),\n                        'position': ranking.get('position', ''),\n                        'title': ranking.get('title', ''),\n                        'url': ranking.get('url', ''),\n                        'timestamp': ranking.get('timestamp', '')\n                    })\n            \n            logger.info(f\"CSV report exported to {filename}\")\n            return filename\n            \n        except Exception as e:\n            logger.error(f\"Error exporting CSV report: {str(e)}\")\n            raise\n    \n    def _group_by_position(self, rankings: List[Dict]) -> Dict:\n        \"\"\"Group rankings by position range\"\"\"\n        groups = {\n            'top_3': [],\n            'top_10': [],\n            'top_50': [],\n            'top_100': [],\n            'not_ranked': []\n        }\n        \n        for ranking in rankings:\n            position = ranking.get('position', 0)\n            \n            if position == 0:\n                groups['not_ranked'].append(ranking)\n            elif position <= 3:\n                groups['top_3'].append(ranking)\n            elif position <= 10:\n                groups['top_10'].append(ranking)\n            elif position <= 50:\n                groups['top_50'].append(ranking)\n            elif position <= 100:\n                groups['top_100'].append(ranking)\n        \n        return groups\n    \n    def _get_top_performers(self, rankings: List[Dict], limit: int = 10) -> List[Dict]:\n        \"\"\"Get top performing keywords\"\"\"\n        ranked = [r for r in rankings if r.get('position', 0) > 0]\n        ranked.sort(key=lambda x: x.get('position', 0))\n        return ranked[:limit]\nEOF\nprint_success \"Created src/report_generator.py\"\n\n# Create src/notifier.py\nprint_status \"Creating src/notifier.py...\"\ncat > src/notifier.py << 'EOF'\n\"\"\"Notification module for ranking changes\"\"\"\n\nimport logging\nfrom typing import Dict, List\n\nlogger = logging.getLogger(__name__)\n\n\nclass Notifier:\n    \"\"\"Send notifications for ranking changes\"\"\"\n    \n    def __init__(self, notification_config: Dict):\n        \"\"\"Initialize notifier\"\"\"\n        self.enabled = notification_config.get('enabled', True)\n        self.email = notification_config.get('email')\n        self.threshold = notification_config.get('position_change_threshold', 3)\n    \n    def notify_results(self, results: List[Dict]) -> bool:\n        \"\"\"Send notification for ranking results\"\"\"\n        if not self.enabled:\n            logger.debug(\"Notifications disabled\")\n            return True\n        \n        try:\n            significant_changes = [\n                r for r in results \n                if r.get('position_change', 0) >= self.threshold\n            ]\n            \n            if significant_changes:\n                self._send_notification(significant_changes)\n                logger.info(f\"Notification sent for {len(significant_changes)} significant changes\")\n            else:\n                logger.debug(\"No significant changes to notify\")\n            \n            return True\n            \n        except Exception as e:\n            logger.error(f\"Error sending notification: {str(e)}\")\n            return False\n    \n    def _send_notification(self, changes: List[Dict]):\n        \"\"\"Send notification message\"\"\"\n        message = self._format_notification(changes)\n        logger.info(f\"Notification message: {message}\")\n    \n    def _format_notification(self, changes: List[Dict]) -> str:\n        \"\"\"Format notification message\"\"\"\n        lines = [\"Keyword Ranking Changes:\\n\"]\n        \n        for change in changes:\n            lines.append(\n                f\"- {change['keyword']}: \"\n                f\"Position {change.get('old_position')} → \"\n                f\"{change.get('position')} (Change: {change.get('position_change')})\"\n            )\n        \n        return \"\\n\".join(lines)\nEOF\nprint_success \"Created src/notifier.py\"\n\n# Create tests/__init__.py\nprint_status \"Creating tests/__init__.py...\"\ncat > tests/__init__.py << 'EOF'\n\"\"\"Tests package\"\"\"\nEOF\nprint_success \"Created tests/__init__.py\"\n\n# Create tests/test_rank_checker.py\nprint_status \"Creating tests/test_rank_checker.py...\"\ncat > tests/test_rank_checker.py << 'EOF'\n\"\"\"Tests for rank checker module\"\"\"\n\nimport pytest\nfrom src.rank_checker import RankChecker\n\n\nclass TestRankChecker:\n    \"\"\"Test RankChecker class\"\"\"\n    \n    @pytest.fixture\n    def checker(self):\n        \"\"\"Create rank checker instance\"\"\"\n        config = {\n            'provider': 'serper',\n            'serper_api_key': 'test_key',\n            'max_results': 100\n        }\n        return RankChecker(config)\n    \n    def test_url_match(self, checker):\n        \"\"\"Test URL matching\"\"\"\n        assert checker._url_match(\n            'https://example.com/page',\n            'https://example.com'\n        )\n        \n        assert checker._url_match(\n            'http://example.com/page',\n            'https://example.com'\n        )\n    \n    def test_url_match_different_domain(self, checker):\n        \"\"\"Test URL matching with different domains\"\"\"\n        assert not checker._url_match(\n            'https://other.com/page',\n            'https://example.com'\n        )\nEOF\nprint_success \"Created tests/test_rank_checker.py\"\n\n# Create tests/test_database.py\nprint_status \"Creating tests/test_database.py...\"\ncat > tests/test_database.py << 'EOF'\n\"\"\"Tests for database module\"\"\"\n\nimport pytest\nimport tempfile\nfrom pathlib import Path\nfrom src.database import Database\n\n\nclass TestDatabase:\n    \"\"\"Test Database class\"\"\"\n    \n    @pytest.fixture\n    def db(self):\n        \"\"\"Create temporary database\"\"\"\n        with tempfile.TemporaryDirectory() as tmpdir:\n            config = {\n                'type': 'sqlite',\n                'path': str(Path(tmpdir) / 'test.db'),\n                'backup_enabled': False\n            }\n            yield Database(config)\n    \n    def test_store_ranking(self, db):\n        \"\"\"Test storing ranking data\"\"\"\n        row_id = db.store_ranking(\n            keyword='test keyword',\n            target_url='https://example.com',\n            position=5\n        )\n        assert row_id > 0\n    \n    def test_get_latest_rankings(self, db):\n        \"\"\"Test retrieving latest rankings\"\"\"\n        db.store_ranking(\n            keyword='test keyword',\n            target_url='https://example.com',\n            position=5\n        )\n        \n        rankings = db.get_latest_rankings()\n        assert len(rankings) > 0\n        assert rankings[0]['keyword'] == 'test keyword'\nEOF\nprint_success \"Created tests/test_database.py\"\n\n# Create requirements.txt\nprint_status \"Creating requirements.txt...\"\ncat > requirements.txt << 'EOF'\nrequests==2.31.0\nbeautifulsoup4==4.12.2\nselenium==4.15.2\npandas==2.1.3\npython-dotenv==1.0.0\napscheduler==3.10.4\njinja2==3.1.2\nmatplotlib==3.8.2\nreportlab==4.0.7\npytest==7.4.3\npython-dateutil==2.8.2\nEOF\nprint_success \"Created requirements.txt\"\n\n# Create config.json\nprint_status \"Creating config.json...\"\ncat > config.json << 'EOF'\n{\n  \"keywords\": [\n    {\n      \"id\": \"kw_1\",\n      \"keyword\": \"best python tutorials\",\n      \"target_url\": \"https://example.com/tutorials\",\n      \"location\": \"US\",\n      \"language\": \"en\",\n      \"track\": true\n    },\n    {\n      \"id\": \"kw_2\",\n      \"keyword\": \"python web development\",\n      \"target_url\": \"https://example.com/web-dev\",\n      \"location\": \"US\",\n      \"language\": \"en\",\n      \"track\": true\n    },\n    {\n      \"id\": \"kw_3\",\n      \"keyword\": \"machine learning guide\",\n      \"target_url\": \"https://example.com/ml-guide\",\n      \"location\": \"US\",\n      \"language\": \"en\",\n      \"track\": true\n    }\n  ],\n  \"api_config\": {\n    \"provider\": \"serper\",\n    \"serper_api_key\": \"${SERPER_API_KEY}\",\n    \"max_results\": 100,\n    \"timeout\": 30\n  },\n  \"database\": {\n    \"type\": \"sqlite\",\n    \"path\": \"./data/rankings.db\",\n    \"backup_enabled\": true\n  },\n  \"check_schedule\": {\n    \"frequency\": \"daily\",\n    \"time\": \"08:00\",\n    \"timezone\": \"UTC\"\n  },\n  \"notifications\": {\n    \"enabled\": true,\n    \"email\": \"${NOTIFICATION_EMAIL}\",\n    \"position_change_threshold\": 3\n  },\n  \"reporting\": {\n    \"generate_daily\": true,\n    \"generate_weekly\": true,\n    \"generate_monthly\": true,\n    \"export_formats\": [\"json\", \"csv\"],\n    \"output_dir\": \"./reports\"\n  }\n}\nEOF\nprint_success \"Created config.json\"\n\n# Create main.py\nprint_status \"Creating main.py...\"\ncat > main.py << 'EOF'\n#!/usr/bin/env python3\n\"\"\"Keyword Ranking Checker Agent - Main entry point\"\"\"\n\nimport argparse\nimport logging\nimport json\nimport os\nfrom datetime import datetime\nfrom pathlib import Path\n\nfrom src.rank_checker import RankChecker\nfrom src.database import Database\nfrom src.report_generator import ReportGenerator\nfrom src.notifier import Notifier\n\n# Setup logging\nlogging.basicConfig(\n    level=logging.INFO,\n    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',\n    handlers=[\n        logging.FileHandler('logs/rank_checker.log'),\n        logging.StreamHandler()\n    ]\n)\nlogger = logging.getLogger(__name__)\n\n\ndef load_config(config_path='config.json'):\n    \"\"\"Load configuration from JSON file\"\"\"\n    try:\n        with open(config_path, 'r') as f:\n            config = json.load(f)\n        \n        api_key = os.getenv('SERPER_API_KEY')\n        if api_key:\n            config['api_config']['serper_api_key'] = api_key\n        \n        email = os.getenv('NOTIFICATION_EMAIL')\n        if email:\n            config['notifications']['email'] = email\n            \n        logger.info(f\"Configuration loaded from {config_path}\")\n        return config\n    except FileNotFoundError:\n        logger.error(f\"Configuration file not found: {config_path}\")\n        return {}\n\n\ndef initialize_directories():\n    \"\"\"Create necessary directories\"\"\"\n    directories = ['logs', 'data', 'reports', 'cache']\n    for directory in directories:\n        Path(directory).mkdir(exist_ok=True)\n\n\ndef check_rankings(config, force=False):\n    \"\"\"Main function to check keyword rankings\"\"\"\n    logger.info(\"Starting keyword ranking check...\")\n    \n    try:\n        db = Database(config['database'])\n        checker = RankChecker(config['api_config'])\n        \n        keywords = config.get('keywords', [])\n        logger.info(f\"Checking {len(keywords)} keywords\")\n        \n        results = []\n        for keyword_config in keywords:\n            if not keyword_config.get('track', True):\n                continue\n                \n            logger.info(f\"Checking keyword: {keyword_config['keyword']}\")\n            \n            try:\n                result = checker.check_keyword(\n                    keyword=keyword_config['keyword'],\n                    target_url=keyword_config['target_url'],\n                    location=keyword_config.get('location', 'US'),\n                    language=keyword_config.get('language', 'en')\n                )\n                \n                db.store_ranking(\n                    keyword=keyword_config['keyword'],\n                    target_url=keyword_config['target_url'],\n                    position=result['position'],\n                    url=result['url'],\n                    serp_features=result.get('serp_features', [])\n                )\n                \n                results.append(result)\n                logger.info(f\"Position: {result['position']} for {keyword_config['keyword']}\")\n                \n            except Exception as e:\n                logger.error(f\"Error checking keyword {keyword_config['keyword']}: {str(e)}\")\n                results.append({\n                    'keyword': keyword_config['keyword'],\n                    'error': str(e)\n                })\n        \n        logger.info(f\"Completed checking {len(results)} keywords\")\n        \n        if config.get('reporting', {}).get('generate_daily'):\n            logger.info(\"Generating daily report...\")\n            generate_report(config, db)\n        \n        if config.get('notifications', {}).get('enabled'):\n            logger.info(\"Sending notifications...\")\n            notifier = Notifier(config['notifications'])\n            notifier.notify_results(results)\n        \n        return results\n        \n    except Exception as e:\n        logger.error(f\"Error during ranking check: {str(e)}\")\n        raise\n\n\ndef generate_report(config, db):\n    \"\"\"Generate ranking report\"\"\"\n    try:\n        generator = ReportGenerator(config['reporting'])\n        latest_rankings = db.get_latest_rankings()\n        history = db.get_ranking_history(days=30)\n        \n        report = generator.generate(\n            latest_rankings=latest_rankings,\n            history=history,\n            timestamp=datetime.now()\n        )\n        \n        for export_format in config['reporting']['export_formats']:\n            generator.export(report, export_format)\n            logger.info(f\"Report exported in {export_format} format\")\n            \n    except Exception as e:\n        logger.error(f\"Error generating report: {str(e)}\")\n        raise\n\n\ndef main():\n    \"\"\"Main entry point\"\"\"\n    parser = argparse.ArgumentParser(description='Keyword Ranking Checker Agent')\n    parser.add_argument('--check', action='store_true', help='Run ranking check')\n    parser.add_argument('--report', action='store_true', help='Generate report')\n    parser.add_argument('--export', choices=['json', 'csv', 'pdf'], help='Export report in specified format')\n    parser.add_argument('--config', default='config.json', help='Path to configuration file')\n    parser.add_argument('--force', action='store_true', help='Force check regardless of schedule')\n    \n    args = parser.parse_args()\n    \n    initialize_directories()\n    config = load_config(args.config)\n    if not config:\n        logger.error(\"Failed to load configuration\")\n        return 1\n    \n    if args.check or not (args.report or args.export):\n        logger.info(\"Running ranking check...\")\n        check_rankings(config, force=args.force)\n    \n    if args.report or args.export:\n        logger.info(\"Generating report...\")\n        db = Database(config['database'])\n        if args.export:\n            config['reporting']['export_formats'] = [args.export]\n        generate_report(config, db)\n    \n    logger.info(\"Completed successfully\")\n    return 0\n\n\nif __name__ == '__main__':\n    exit(main())\nEOF\nchmod +x main.py\nprint_success \"Created main.py\"\n\n# Create .github/workflows/daily-ranking-check.yml\nprint_status \"Creating .github/workflows/daily-ranking-check.yml...\"\ncat > .github/workflows/daily-ranking-check.yml << 'EOF'\nname: Daily Keyword Ranking Check\n\non:\n  schedule:\n    - cron: '0 8 * * *'  # Daily at 8 AM UTC\n  workflow_dispatch:  # Allow manual trigger\n\njobs:\n  check-rankings:\n    runs-on: ubuntu-latest\n    \n    steps:\n      - name: Checkout repository\n        uses: actions/checkout@v4\n      \n      - name: Set up Python\n        uses: actions/setup-python@v4\n        with:\n          python-version: '3.11'\n      \n      - name: Install dependencies\n        run: |\n          python -m pip install --upgrade pip\n          pip install -r requirements.txt\n      \n      - name: Run ranking check\n        env:\n          SERPER_API_KEY: ${{ secrets.SERPER_API_KEY }}\n          NOTIFICATION_EMAIL: ${{ secrets.NOTIFICATION_EMAIL }}\n        run: |\n          python main.py --check --report\n      \n      - name: Upload reports\n        uses: actions/upload-artifact@v3\n        with:\n          name: ranking-reports\n          path: reports/\n          retention-days: 30\n      \n      - name: Commit report to repository\n        run: |\n          git config --global user.name \"Ranking Bot\"\n          git config --global user.email \"bot@example.com\"\n          git add reports/\n          git commit -m \"Update ranking reports - $(date +%Y-%m-%d)\" || true\n          git push\n        if: always()\nEOF\nprint_success \"Created .github/workflows/daily-ranking-check.yml\"\n\n# Create .gitignore\nprint_status \"Creating .gitignore...\"\ncat > .gitignore << 'EOF'\n# Python\n__pycache__/\n*.py[cod]\n*$py.class\n*.so\n.Python\nbuild/\ndevelop-eggs/\ndist/\ndownloads/\neggs/\n.eggs/\nlib/\nlib64/\nparts/\nsdist/\nvar/\nwheels/\n*.egg-info/\n.installed.cfg\n*.egg\n\n# Virtual environments\nvenv/\nENV/\nenv/\n.venv\n\n# IDE\n.vscode/\n.idea/\n*.swp\n*.swo\n*~\n.DS_Store\n\n# Project specific\ndata/*.db\ndata/*.db-*\nlogs/*.log\nreports/*\n!reports/.gitkeep\n*.cache\n.env\n.env.local\nconfig.local.json\n\n# OS\n.DS_Store\nThumbs.db\nEOF\nprint_success \"Created .gitignore\"\n\n# Create .gitkeep files\nprint_status \"Creating .gitkeep files...\"\ntouch reports/.gitkeep\ntouch logs/.gitkeep\ntouch data/.gitkeep\nprint_success \"Created .gitkeep files\"\n\necho \"\"\necho \"${GREEN}================================================${NC}\"\necho \"${GREEN}✓ Setup Complete!${NC}\"\necho \"${GREEN}================================================${NC}\"\necho \"\"\nprint_success \"All project files have been created successfully!\"\necho \"\"\necho \"${BLUE}Next Steps:${NC}\"\necho \"1. Edit config.json with your keywords and settings\"\necho \"2. Install dependencies: pip install -r requirements.txt\"\necho \"3. Get Serper API key from https://serper.dev/\"\necho \"4. Set environment variables:\"\necho \"   export SERPER_API_KEY=your_api_key_here\"\necho \"   export NOTIFICATION_EMAIL=your@email.com\"\necho \"5. Test locally: python main.py --check --report\"\necho \"6. Commit and push to GitHub\"\necho \"7. Add GitHub Secrets in repository settings\"\necho \"\"\necho \"${YELLOW}GitHub Secrets to Add:${NC}\"\necho \"  - SERPER_API_KEY\"\necho \"  - NOTIFICATION_EMAIL\"\necho \"\"\necho \"${GREEN}Happy tracking! 🚀${NC}\"\necho \"\"\n"